@* A single Kanban column showing header, task cards, and an optional add-task form *@

<div class="board-column">
    <div class="column-header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <BoardTaskCard Task="task"
                           ShowMoveLeft="ShowMoveLeft"
                           ShowMoveRight="ShowMoveRight"
                           OnMoveLeft="() => HandleMoveLeft(task)"
                           OnMoveRight="() => HandleMoveRight(task)" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <BoardAddTaskForm OnSave="HandleAddTask" OnCancel="HideForm" />
        }
        else
        {
            <button class="btn-add-task" @onclick="ShowForm">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public string Status { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<(TaskItem Task, string Direction)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<BoardAddTaskForm.NewTaskModel> OnAddTask { get; set; }

    private bool showAddForm;

    private void ShowForm() => showAddForm = true;
    private void HideForm() => showAddForm = false;

    private async Task HandleMoveLeft(TaskItem task)
    {
        await OnMoveTask.InvokeAsync((task, "left"));
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        await OnMoveTask.InvokeAsync((task, "right"));
    }

    private async Task HandleAddTask(BoardAddTaskForm.NewTaskModel model)
    {
        await OnAddTask.InvokeAsync(model);
        showAddForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p>Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>Error: @errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="GetTasksByStatus("To Do").Count"
                   InProgressCount="GetTasksByStatus("In Progress").Count"
                   DoneCount="GetTasksByStatus("Done").Count"
                   OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="board-columns">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="GetFilteredTasksByStatus("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="model => HandleAddTask(model, "To Do")" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="GetFilteredTasksByStatus("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="model => HandleAddTask(model, "In Progress")" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="GetFilteredTasksByStatus("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="model => HandleAddTask(model, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetTasksByStatus(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksByStatus(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText)
                || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private async Task HandleMoveTask((TaskItem Task, string Direction) args)
    {
        var currentIndex = Array.IndexOf(Statuses, args.Task.Status);
        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.Task.Id, newStatus);
            allTasks = allTasks.Select(t => t.Id == args.Task.Id
                ? t with { Status = newStatus }
                : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask(BoardAddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

