    {
        var currentIndex = Array.IndexOf(Statuses, args.Task.Status);
        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.Task.Id, newStatus);
            allTasks = allTasks.Select(t => t.Id == args.Task.Id
                ? t with { Status = newStatus }
                : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask(BoardAddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

